import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Turing Post — 2026-04-14","description":"","frontmatter":{"title":"Turing Post — 2026-04-14","date":"2026-04-14T00:00:00.000Z","source":"Turing Post","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-14-turing-post.md","filePath":"research/ai-news/2026-04/2026-04-14-turing-post.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-04/2026-04-14-turing-post.md"};function i(s,e,l,h,p,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🏛️-turing-post-—-2026-04-14" tabindex="-1">🏛️ Turing Post — 2026-04-14 <a class="header-anchor" href="#🏛️-turing-post-—-2026-04-14" aria-label="Permalink to &quot;🏛️ Turing Post — 2026-04-14&quot;">​</a></h1><blockquote><p>Ksenia Se 主持，95k+ 訂閱；AI/ML 政策、地緣政治與深度洞察 來源：<a href="https://turingpost.substack.com/feed" target="_blank" rel="noreferrer">Turing Post</a></p></blockquote><hr><h2 id="fod-148-messy-middle-of-installation-gpt-meets-gpt" tabindex="-1"><a href="https://turingpost.substack.com/p/fod148-messy-middle-of-installation" target="_blank" rel="noreferrer">FOD#148: Messy Middle of Installation -&gt; GPT Meets GPT</a> <a class="header-anchor" href="#fod-148-messy-middle-of-installation-gpt-meets-gpt" aria-label="Permalink to &quot;[FOD#148: Messy Middle of Installation -&gt; GPT Meets GPT](https://turingpost.substack.com/p/fod148-messy-middle-of-installation)&quot;">​</a></h2><p><em>🏛️ Turing Post | 2026-04-14</em></p><p>This Week in Turing Post:</p><p>Wednesday / AI 101 series: What Is a Token (and why it runs AI)?</p><p>Friday / Interview: an amazing conversation on AI literacy and rethinking education with Neeru Khosla, co-founder of the CK-12 Foundation</p><p>📆From our partners: How to govern multi-agent systems at scale?</p><p>We know that the hardest part of multi-agent systems isn’t building them, but governing them at scale. <a href="https://galileo.ai/webinar/governing-multi-agent-systems-at-scale?utm_medium=paid&amp;utm_source=turing_post&amp;utm_campaign=sponsorship" target="_blank" rel="noreferrer">Join</a> Galileo co-founder Yash Sheth and CrewAI founder Joao Moura for a live session on April 21st to learn how to run multi-agent systems safely at scale, covering behavior, cost, and compliance across first and third-party agents.</p><p>You’ll learn how to:</p><p>Enforce safety and security policies in agents.</p><p>Steer agents to the best models and fallback tools at runtime to improve accuracy and control token costs</p><p>Govern all your agents, whether CrewAI, internal or third-party, with one centralized set of policies</p><p>Include non-technical stakeholders (such as risk and compliance) in writing or maintaining policies – no coding required</p><p>To the main topic →</p><p>GPT Meets GPT: The Economics Nobody’s Talking About</p><p>Economists have been studying GPTs for decades. They just meant a different kind. In economics, a General Purpose Technology is one that restructures entire economies rather than single industries – steam, electricity, computing. Carlota Perez mapped their lifecycle into a pattern: a turbulent installation phase full of speculation and uneven adoption, followed by a deployment phase where the gains actually compound. The interesting part is the gap between the two. That’s where we are right now – except this time the General Purpose Technology shares its acronym with the thing that’s causing all the trouble (GPT in AI – generative pre-trained transformer).</p><p>This week offered three dispatches from that gap, and together they paint a picture that is worth our attention.</p><p>On April 6, OpenAI <a href="https://cdn.openai.com/pdf/561e7512-253e-424b-9734-ef4098440601/Industrial%20Policy%20for%20the%20Intelligence%20Age.pdf" target="_blank" rel="noreferrer">published</a> a 13-page policy blueprint called Industrial Policy for the Intelligence Age: Ideas to Keep People First. It proposes public wealth funds, portable benefits, worker participation in AI deployment, and a rethinking of payroll-based tax systems for an economy where wages may no longer be the primary source of national income. OpenAI frames these as “ambitious, but intentionally early and exploratory.” Whatever you think of the messenger, the underlying logic tracks directly to a real problem in economics known as Baumol’s cost disease: sectors where productivity is hard to improve – healthcare, education, government – see costs rise relentlessly relative to everything else. AI potentially cures Baumol’s disease by making intelligence-intensive services scalable for the first time. And that changes the fiscal math of entire nations.</p><p>Ensuring that AI expands access, agency, and opportunity is a central challenge as we move towards superintelligence. We should aim for a future where superintelligence benefits everyone.</p><p>OpenAI</p><p>They are not alone in trying to grasp our future economics in a more tangible way. Today, Workshop Labs announced it’s joining Thinking Machines, Mira Murati’s lab. Workshop Labs <a href="https://intelligence-curse.ai/" target="_blank" rel="noreferrer">grew out</a> of The Intelligence Curse, an essay series arguing that when AI replaces labor as the dominant factor of production, powerful actors – states, corporations – lose their structural incentive to invest in people. Their founders write that they “started by asking what happens if AI takes everyone’s job” and “didn’t like that answer.” In Solow growth model terms, they’re arguing the elasticity of substitution between capital and labor is approaching infinity – and that this breaks the social contract, not just the job market. They suggest the following solution: AI systems aligned to individual users, decentralizing ownership rather than concentrating it. That Murati’s lab absorbed this team tells you where at least one frontier lab thinks the real problem lives.</p><p>There’s a path for AI to make humans matter more.</p><p>Mira Murati</p><p>Meanwhile, the Stanford HAI 2026 AI Index <a href="https://hai.stanford.edu/ai-index/2026-ai-index-report" target="_blank" rel="noreferrer">reported</a> that generative AI reached 53% population adoption within three years – faster than the PC or the internet. The estimated value of these tools to US consumers reached $172 billion annually by early 2026, with the median value per user tripling in a single year. Paul Romer won the Nobel Prize for showing that ideas are non-rival goods – one person using an idea doesn’t stop another from using it. That was elegant theory in 2018. In 2026, it’s an observable market condition with a $172 billion price tag.</p><p>But Perez’s framework predicts something else about the installation phase: adoption is wildly uneven. And it is. Sometimes in very unexpected places. Steve Yegge <a href="https://x.com/Steve_Yegge/status/2043747998740689171" target="_blank" rel="noreferrer">shared</a> a conversation with a long-time Google tech director revealing that Google’s internal AI adoption looks roughly like any average enterprise –20% power users, 60% on chat tools, 20% refusers. The Googler explains to him that it happened because of an 18-month hiring freeze: no one moves between companies, so no one arrives from the outside to calibrate how far behind Google are. Yegge calls it “the Great Siloing.”</p><p>So here’s the picture. The original GPT economists warned us: General Purpose Technologies don’t distribute their gains evenly or on schedule. The new GPTs are confirming the theory in real time. We are nowhere close to understanding the economic reality that awaits around the corner. But at least the abundance frameworks are now being drafted in real time.</p><p>This is both exciting and deeply concerning, because we’re entering genuinely uncharted territory. Throughout history, only a thin stratum of the population ever had to figure out how to live in abundance. The aristocracy was, in its own imperfect way, an experiment in what humans do when freed from the necessity of labor – and the results were a mixed bag of patronage, philosophy, and spectacular dysfunction. But we have never been in a position where abundance could plausibly be spread across an entire population. There is no playbook for this. We don’t even have the right mindset for it yet – centuries of equating human value with economic output don’t dissolve overnight. (I <a href="https://www.turingpost.com/p/fod112" target="_blank" rel="noreferrer">wrote about this before</a> – the concept of an “aristocracy of all” that AI could make possible, if we choose to build for it.)</p><p>The frameworks are being written. I’m not sure any of us are ready (yet) for what they describe. We are in the messy middle of installation.</p><p>→ If any of those thoughts resonate with you – share them across your social networks. Let’s keep the conversation going.</p><p>Topic 2: Meta AI and KAUST just proposed a new kind of machine: a Neural Computer –where the neural network doesn’t use a computer, it IS the computer. Computation, memory, and I/O all collapse into one learned runtime. Sounds revolutionary. But is it? And will it even work? <a href="https://www.youtube.com/watch?v=z_be7EOkBRo" target="_blank" rel="noreferrer">Let’s discuss </a><a href="https://www.youtube.com/watch?v=z_be7EOkBRo" target="_blank" rel="noreferrer">→</a></p><p>Follow us on 🎥<a href="https://www.youtube.com/@RealTuringPost" target="_blank" rel="noreferrer"> YouTube</a> <a href="https://x.com/TheTuringPost" target="_blank" rel="noreferrer">Twitter</a> <a href="https://huggingface.co/Kseniase" target="_blank" rel="noreferrer"> Hugging Face </a>🤗</p><p>Twitter Library</p><p><a href="https://www.turingpost.com/p/aisecuritytools" target="_blank" rel="noreferrer">10 Open Projects for AI Security</a></p><p>We are reading/watching/learning:</p><p><a href="https://www.interconnects.ai/p/the-inevitable-need-for-an-open-model" target="_blank" rel="noreferrer">The inevitable need for an open model consortium</a> by Nathan Lambert</p><p><a href="https://www.youtube.com/watch?v=C0gErQtnNFE" target="_blank" rel="noreferrer">The Hardest Problem AI Ever Solved, with Google DeepMind CEO</a> by Cleo Abram</p><p>and one from history (thanks, Raymond Pettit, for sending this over): <a href="https://www.youtube.com/watch?v=Ozipf13jRr4" target="_blank" rel="noreferrer">John McCarthy (1927-2011): Artificial Intelligence (complete)</a></p><p>News from the usual suspects ™ (rivals rivals rivals)</p><p>AI Giants Call a Truce (Sort Of) OpenAI, Anthropic, and Google – usually sparring in public – are <a href="https://www.bloomberg.com/news/articles/2026-04-06/openai-anthropic-google-unite-to-combat-model-copying-in-china?utm_source=chatgpt.com" target="_blank" rel="noreferrer">sharing</a> intel to stop rivals from copying their models on the cheap. The culprit: “adversarial distillation,” a clever shortcut that risks gutting profits and safety guardrails alike. When competitors start learning from your answers instead of your code, even rivals become allies.</p><p>Anthropic’s Glasswing Gambit Anthropic unveils Project Glasswing, rallying tech heavyweights from AWS to Microsoft and Google (but not OprnAI) in a race against their own creation. Its Mythos model can uncover – and exploit – software flaws better than most humans, already exposing thousands of critical vulnerabilities →<a href="https://www.anthropic.com/project/glasswing" target="_blank" rel="noreferrer">check their write-up</a> and our video about it:</p><p>Meanwhile, OpenAI:</p><p>Codex Finds Its Way into Claude’s Workflow OpenAI has <a href="https://github.com/openai/codex-plugin-cc" target="_blank" rel="noreferrer">released</a> a plugin that lets developers call Codex directly from within Anthropic’s Claude Code environment—an unexpected bit of interoperability in a competitive landscape. The tool handles reviews, debugging, and delegated tasks without leaving the workflow. In a world of walled gardens, this feels more like a side door—practical, if not entirely philosophical.</p><p>sharpens its enterprise pitch An internal memo from OpenAI’s chief revenue officer, Denise Dresser, <a href="https://www.theverge.com/ai-artificial-intelligence/911118/openai-memo-cro-ai-competition-anthropic" target="_blank" rel="noreferrer">lays out </a>a familiar ambition with renewed urgency: keep users inside the ecosystem and deepen ties with enterprise clients. The note stresses that a broader product suite makes OpenAI harder to displace, while also acknowledging fiercer competition – especially from Anthropic. In AI, being the best this week is charming, but being hard to replace is business.</p><p>Google Doubles Down on Custom Silicon Broadcom and Google <a href="https://www.reuters.com/business/broadcom-signs-long-term-deal-develop-googles-custom-ai-chips-2026-04-06/" target="_blank" rel="noreferrer">have inked</a> a long-term deal to build the next generations of AI chips through 2031, signaling Google’s intent to rely less on Nvidia’s costly GPUs. Meanwhile, Anthropic secures access to massive compute capacity tied to these chips. The takeaway: in AI, owning the silicon – or at least securing it early – matter as much as the models themselves.</p><p>AI Giants Call a Truce (Sort Of) OpenAI, Anthropic, and Google – usually sparring in public – are <a href="https://www.bloomberg.com/news/articles/2026-04-06/openai-anthropic-google-unite-to-combat-model-copying-in-china?utm_source=chatgpt.com" target="_blank" rel="noreferrer">sharing</a> intel to stop rivals from copying their models on the cheap. The culprit: “adversarial distillation,” a clever shortcut that risks gutting profits and safety guardrails alike. When competitors start learning from your answers instead of your code, even rivals become allies.</p><p>Anthropic’s Glasswing Gambit Anthropic unveils Project Glasswing, rallying tech heavyweights from AWS to Microsoft and Google (but not OprnAI) in a race against their own creation. Its Mythos model can uncover – and exploit – software flaws better than most humans, already exposing thousands of critical vulnerabilities →<a href="https://www.anthropic.com/project/glasswing" target="_blank" rel="noreferrer">check their write-up</a> and our video about it:</p><p>Meanwhile, OpenAI:</p><p>Codex Finds Its Way into Claude’s Workflow OpenAI has <a href="https://github.com/openai/codex-plugin-cc" target="_blank" rel="noreferrer">released</a> a plugin that lets developers call Codex directly from within Anthropic’s Claude Code environment—an unexpected bit of interoperability in a competitive landscape. The tool handles reviews, debugging, and delegated tasks without leaving the workflow. In a world of walled gardens, this feels more like a side door—practical, if not entirely philosophical.</p><p>sharpens its enterprise pitch An internal memo from OpenAI’s chief revenue officer, Denise Dresser, <a href="https://www.theverge.com/ai-artificial-intelligence/911118/openai-memo-cro-ai-competition-anthropic" target="_blank" rel="noreferrer">lays out </a>a familiar ambition with renewed urgency: keep users inside the ecosystem and deepen ties with enterprise clients. The note stresses that a broader product suite makes OpenAI harder to displace, while also acknowledging fiercer competition – especially from Anthropic. In AI, being the best this week is charming, but being hard to replace is business.</p><p>Google Doubles Down on Custom Silicon Broadcom and Google <a href="https://www.reuters.com/business/broadcom-signs-long-term-deal-develop-googles-custom-ai-chips-2026-04-06/" target="_blank" rel="noreferrer">have inked</a> a long-term deal to build the next generations of AI chips through 2031, signaling Google’s intent to rely less on Nvidia’s costly GPUs. Meanwhile, Anthropic secures access to massive compute capacity tied to these chips. The takeaway: in AI, owning the silicon – or at least securing it early – matter as much as the models themselves.</p><p>🔦 Models and Agents Highlight</p><p>OpenClaw 2026.3.28 – new provider support, approval hooks, richer channel bindings, image tooling<a href="http://google.com/search?q=OpenClaw+2026.3.28&amp;rlz=1C5CHFA_enUS804US805&amp;oq=OpenClaw+2026.3.28&amp;gs_lcrp=EgZjaHJvbWUyBggAEEUYOTIGCAEQRRg8MgYIAhBFGDwyBggDEEUYPdIBBzE0MGowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8" target="_blank" rel="noreferrer"> →check their GitHub</a></p><p>MiniMax M2.7 — self-evolving agent model, open-sourced. Improves behavior from experience, not static fine-tuning. Competitive with top closed models on agentic benchmarks <a href="https://x.com/MiniMax_AI/status/2043132047397659000" target="_blank" rel="noreferrer">→read their announcement</a></p><p>LFM2.5-VL-450M – Liquid AI. 450M parameter vision-language model. Multilingual support, bounding box prediction, sub-250ms edge inference. Step toward practical on-device multimodal AI <a href="https://www.liquid.ai/blog/lfm2-5-vl-450m" target="_blank" rel="noreferrer">→read their blog</a></p><p>GLM-5.1 – topped open-source coding benchmarks. Alibaba closing gap with Western alternatives <a href="https://z.ai/blog/glm-5.1" target="_blank" rel="noreferrer">→read their blog</a></p><p>A1 – fully transparent open-source vision-language-action model for robotics. Uses adaptive truncated inference to cut latency and compute while keeping strong manipulation performance, with the full training and evaluation stack released for reproducibility <a href="https://www.arxiv.org/abs/2604.05672" target="_blank" rel="noreferrer">→read the paper</a></p><p>Research</p><p>Trends we see:</p><p>Test-time adaptation is becoming a first-class paradigm Not just fine-tuning, but models that keep updating while running.</p><p>The system boundary is moving inward Neural Computers, world models, agent environments all point to the same direction: the model is no longer just reasoning about a system – it is the system.</p><hr>',63)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
